def move_one_ball(arr):
    if not arr:
        return True  # An empty array is considered sorted.

    n = len(arr)
    count = 0  # Count how many times the order breaks

    for i in range(n):
        if arr[i] > arr[(i + 1) % n]:  # Compare current element with the next (circular)
            count += 1

    # There should be at most one point where the order breaks
    return count <= 1

# Example usage:
print(move_one_ball([3, 4, 5, 1, 2]))  # True
print(move_one_ball([3, 5, 4, 1, 2]))  # False

def is_palindrome(num):
    return str(num) == str(num)[::-1]

def even_odd_palindrome(n):
    even_count = 0
    odd_count = 0

    for i in range(1, n + 1):
        if is_palindrome(i):
            if i % 2 == 0:
                even_count += 1
            else:
                odd_count += 1

    return (even_count, odd_count)

# Example usage:
print(even_odd_palindrome(3))  # Output: (1, 2)
print(even_odd_palindrome(12)) # Output: (4, 6)

