def max_element(l: list):
    if not l:
        return None  # Return None for an empty list
    max_value = l[0]  # Assume the first element is the maximum
    for element in l:
        if element > max_value:
            max_value = element  # Update max_value if a larger element is found
    return max_value

# Example usage:
print(max_element([1, 2, 3]))  # Output: 3
print(max_element([5, 3, -5, 2, -3, 3, 9, 0, 123, 1, -10]))  # Output: 123

def choose_num(x, y):
    # Ensure x is less than or equal to y
    if x > y:
        return -1

    # Start from y and find the largest even number
    for num in range(y, x - 1, -1):
        if num % 2 == 0:
            return num

    return -1

# Example usage:
print(choose_num(12, 15))  # Output: 14
print(choose_num(13, 12))  # Output: -1

