def largest_divisor(n: int) -> int:
    # Start from n-1 and go downwards to find the largest divisor
    for i in range(n - 1, 0, -1):
        if n % i == 0:
            return i
    return None  # In case n is 1, there is no divisor smaller than 1

# Example usage:
print(largest_divisor(15))  # Output: 5

def largest_divisor(n: int) -> int:
    # Start checking from n-1 down to 1
    for i in range(n - 1, 0, -1):
        if n % i == 0:  # Check if i is a divisor of n
            return i  # Return the first (largest) divisor found
    return 1  # In case n is 1, return 1 (the only divisor)

# Example usage
print(largest_divisor(15))  # Output: 5

