def can_arrange(arr):
    # Iterate through the array in reverse order
    for i in range(len(arr) - 1, 0, -1):
        # Check if the current element is not greater than or equal to the previous element
        if arr[i] < arr[i - 1]:
            return i  # Return the current index
    return -1  # Return -1 if no such element exists

# Test cases
print(can_arrange([1, 2, 4, 3, 5]))  # Output: 3
print(can_arrange([1, 2, 3]))        # Output: -1

def can_arrange(arr):
    # Iterate through the array from the second last element to the first
    for i in range(len(arr) - 1, 0, -1):
        # Check if the current element is not greater than or equal to the previous element
        if arr[i] < arr[i - 1]:
            return i  # Return the index if the condition is met
    return -1  # Return -1 if no such element exists

# Example usage:
print(can_arrange([1, 2, 4, 3, 5]))  # Output: 3
print(can_arrange([1, 2, 3]))         # Output: -1

def can_arrange(arr):
    # Iterate from the second to last element to the first element
    for i in range(len(arr) - 1, 0, -1):
        # Check if the current element is less than the previous element
        if arr[i] < arr[i - 1]:
            return i  # Return the index of the element
    return -1  # Return -1 if no such element is found

# Test cases
print(can_arrange([1, 2, 4, 3, 5]))  # Output: 3
print(can_arrange([1, 2, 3]))        # Output: -1

